package unverified;

import metadata.BehavioralDifference;
import metadata.DifferenceType;

import org.junit.jupiter.api.Test;

import static unverified.ClonePairGenericInvocationTestSupport.*;

class ClonePair4241DifferenceFindingTest {

    private final ClonePair4241 subject = new ClonePair4241();

    /**
     * Generated by Codex (GPT-5.5).
     * Difference type: return_value.
     * Difference manifestation: the methods return different values.
     */
    @Test
    @BehavioralDifference(DifferenceType.RETURN_VALUE)
    void methodsDisagreeOnGeneratedInput() {
        Object[] inputs = new Object[]{Float.POSITIVE_INFINITY, Float.NaN, Float.NaN};
        InvocationOutcome method1Outcome = capture(values -> subject.method1(((Float) values[0]).floatValue(), ((Float) values[1]).floatValue(), ((Float) values[2]).floatValue()), inputs);
        InvocationOutcome method2Outcome = capture(values -> subject.method2(((Float) values[0]).floatValue(), ((Float) values[1]).floatValue(), ((Float) values[2]).floatValue()), inputs);

        assertCoreOutcome(
            method1Outcome,
            "OK",
            "Float(NaN)",
            null,
            "java.lang.Object[][Float(Infinity),Float(NaN),Float(NaN)]",
            "java.lang.Object[][Float(Infinity),Float(NaN),Float(NaN)]"
        );
        assertCoreOutcome(
            method2Outcome,
            "OK",
            "Float(Infinity)",
            null,
            "java.lang.Object[][Float(Infinity),Float(NaN),Float(NaN)]",
            "java.lang.Object[][Float(Infinity),Float(NaN),Float(NaN)]"
        );
        assertTextEquals("stdout", "", method1Outcome.stdout);
        assertTextEquals("stdout", "", method2Outcome.stdout);
        assertTextEquals("stderr", "", method1Outcome.stderr);
        assertTextEquals("stderr", "", method2Outcome.stderr);
        assertDifferent(method1Outcome, method2Outcome);
    }
}
